1	export interface TelegramRichMessageDraft {
2	  markdown: string;
3	}
4	
5	export function renderTelegramRichDraft(text: string): TelegramRichMessageDraft {
6	  return { markdown: text.replace(/\r\n/g, "\n") };
7	}
8	
9	export async function tryEditRichMessageDraft(
10	  api: unknown,
11	  chatId: number,
12	  messageId: number,
13	  text: string,
14	  extra: Record<string, unknown> = {},
15	): Promise<boolean> {
16	  // 注意：真 grammY 的 api.raw 是 Proxy，任何 method 名都回傳 callable，
17	  // 所以 typeof guard 只對 fake api（測試）或非 grammY adapter 有效；
18	  // 真正的「不支援」偵測靠下面的 catch（server 拒絕時回 false 讓呼叫端走 plain fallback）。
19	  const raw = (api as { raw?: { editMessageText?: unknown } }).raw;
20	  const method = raw?.editMessageText;
21	  if (typeof method !== "function") return false;
22	  const rich_message = renderTelegramRichDraft(text);
23	  try {
24	    await method.call(raw, {
25	      chat_id: chatId,
26	      message_id: messageId,
27	      ...extra,
28	      rich_message,
29	    });
30	    return true;
31	  } catch {
32	    // Rich edit 失敗（含 400 identical / server 不支援 rich_message）→
33	    // 回 false 讓呼叫端退回 plain editMessageText，不讓例外吃掉整幀。
34	    return false;
35	  }
36	}
37	
38	/**
39	 * Send a new rich message (for multi-chunk continuation messages).
