export interface TelegramRichMessageDraft {
  markdown: string;
}

export function renderTelegramRichDraft(text: string): TelegramRichMessageDraft {
  return { markdown: text.replace(/\r\n/g, "\n") };
}

export async function tryEditRichMessageDraft(
  api: unknown,
  chatId: number,
  messageId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<boolean> {
  // 注意：真 grammY 的 api.raw 是 Proxy，任何 method 名都回傳 callable，
  // 所以 typeof guard 只對 fake api（測試）或非 grammY adapter 有效；
  // 真正的「不支援」偵測靠下面的 catch（server 拒絕時回 false 讓呼叫端走 plain fallback）。
  const raw = (api as { raw?: { editMessageText?: unknown } }).raw;
  const method = raw?.editMessageText;
  if (typeof method !== "function") return false;
  const rich_message = renderTelegramRichDraft(text);
  try {
    await method.call(raw, {
      chat_id: chatId,
      message_id: messageId,
      ...extra,
      rich_message,
    });
    return true;
  } catch {
    // Rich edit 失敗（含 400 identical / server 不支援 rich_message）→
    // 回 false 讓呼叫端退回 plain editMessageText，不讓例外吃掉整幀。
    return false;
  }
}

/**
 * Send a new rich message (for multi-chunk continuation messages).
 * Rich sends go through the dedicated Bot API 10.1 `sendRichMessage` method —
 * `sendMessage` ignores a `rich_message` param and delivers plain text.
 * Returns the sent message object, or undefined if rich send is unsupported
 * or rejected (caller falls back to a plain send).
 */
/**
 * 發送或更新 ephemeral draft（Bot API 10.1 sendMessageDraft / sendRichMessageDraft）。
 * 同 draftId 重複呼叫 = 全量替換 + 動畫過渡；空 text = 顯示 "Thinking…"。
 * Draft 是 30s TTL ephemeral，最終須 sendRichMessage/sendMessage 持久化。
 * 僅 private chat 可用；失敗回 false 讓呼叫端走 placeholder fallback。
 */
export async function trySendDraft(
  api: unknown,
  chatId: number,
  draftId: number,
  text: string,
  useRich: boolean,
): Promise<boolean> {
  const raw = (api as { raw?: Record<string, unknown> }).raw;
  if (!raw) return false;

  if (useRich) {
    const method = raw.sendRichMessageDraft;
    if (typeof method !== "function") return false;
    const rich_message = renderTelegramRichDraft(text);
    try {
      await (method as Function).call(raw, {
        chat_id: chatId,
        draft_id: draftId,
        rich_message,
      });
      return true;
    } catch {
      return false;
    }
  }

  // plain draft
  const method = raw.sendMessageDraft;
  if (typeof method !== "function") return false;
  try {
    await (method as Function).call(raw, {
      chat_id: chatId,
      draft_id: draftId,
      text: text || undefined, // undefined → "Thinking…" placeholder
    });
    return true;
  } catch {
    return false;
  }
}

export async function trySendRichMessage(
  api: unknown,
  chatId: number,
  text: string,
  extra: Record<string, unknown> = {},
): Promise<{ message_id: number } | undefined> {
  const raw = (api as { raw?: { sendRichMessage?: unknown } }).raw;
  const method = raw?.sendRichMessage;
  if (typeof method !== "function") return undefined;
  const rich_message = renderTelegramRichDraft(text);
  try {
    const result = await method.call(raw, {
      chat_id: chatId,
      ...extra,
      rich_message,
    });
    return result as { message_id: number } | undefined;
  } catch {
    return undefined;
  }
}

