662	          // runPrompt isn't listening, so route it to the debounced orphan
663	          // flusher instead of the live-turn buffer. Thought chunks are never
664	          // user-facing, so only real message chunks take this path.
665	          if (up.sessionUpdate === "agent_message_chunk" && !session.inflight) {
666	            this.appendOrphan(session, content.text);
667	            break;
668	          }
669	          const wasEmpty = session.buffer.length === 0 && !session.thinkingBuffer;
670	          if (up.sessionUpdate === "agent_thought_chunk") {
