677	          // Early-capture RELAY_DELEGATE tokens during streaming.
678	          // Workaround: Kiro CLI may strip <<...>> from final text in pure-text turns,
679	          // but streaming chunks arrive unfiltered. We capture complete tokens here
680	          // so the final-render path can fall back to them if normal extraction finds nothing.
681	          // Inline/fenced code examples must stay inert, matching final token extraction.
682	          const captured = captureRelayDelegateTokensFromText(session.buffer, session._streamingDelegates ?? []);
