console.log('lines:', lines.length);
// 統計 update 種類 + prompt 次數
const counts={};
let prompts=0, chunks=0, chunkChars=0;
const texts=[];
for(const l of lines){
  let e; try{e=JSON.parse(l)}catch{continue}
  const m=e.method||e.dir&&e.msg?.method||'';
  const method = e.method ?? e.msg?.method ?? e.payload?.method ?? '';
  if(method==='session/prompt'){prompts++;}
  const u = e.params?.update?.sessionUpdate ?? e.msg?.params?.update?.sessionUpdate ?? e.payload?.params?.update?.sessionUpdate;
  if(u){counts[u]=(counts[u]||0)+1;
    if(u==='agent_message_chunk'){
      const t=(e.params??e.msg?.params??e.payload?.params)?.update?.content?.text||'';
      chunks++; chunkChars+=t.length; texts.push(t);
    }
  }
}
console.log('prompts:',prompts,'updates:',JSON.stringify(counts));
console.log('message chars total:',chunkChars);
console.log('--- last 500 chars of concatenated message text ---');
console.log(texts.join('').slice(-500));
"

