import { readFileSync } from "node:fs";
import ts from "typescript";

const source = readFileSync("src/telegram-rich-renderer.ts", "utf8");
const js = ts.transpileModule(source, {
  compilerOptions: {
    module: ts.ModuleKind.ES2022,
    target: ts.ScriptTarget.ES2022,
  },
}).outputText;

const mod = await import(`data:text/javascript;base64,${Buffer.from(js).toString("base64")}`);
const { trySendDraft, trySendRichMessage } = mod;

function assert(name, condition, detail = "") {
  if (!condition) {
    throw new Error(`FAIL: ${name}${detail ? `: ${detail}` : ""}`);
  }
  console.log(`ok - ${name}`);
}

// ─── trySendDraft: plain mode ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendMessageDraft: async (params) => { calls.push({ method: "sendMessageDraft", ...params }); return true; },
      sendRichMessageDraft: async (params) => { calls.push({ method: "sendRichMessageDraft", ...params }); return true; },
    },
  };

  // 空 text → "Thinking…" placeholder（text = undefined）
  const ok1 = await trySendDraft(fakeApi, 123, 1, "", false);
  assert("plain draft with empty text returns true", ok1);
  assert("plain draft calls sendMessageDraft", calls[0].method === "sendMessageDraft");
  assert("plain draft sends chat_id", calls[0].chat_id === 123);
  assert("plain draft sends draft_id", calls[0].draft_id === 1);
  assert("plain draft empty text → undefined (Thinking… placeholder)", calls[0].text === undefined);

  // 有 text
  calls.length = 0;
  const ok2 = await trySendDraft(fakeApi, 123, 1, "Hello world", false);
  assert("plain draft with text returns true", ok2);
  assert("plain draft sends text content", calls[0].text === "Hello world");
}

// ─── trySendDraft: rich mode ───

{
  const calls = [];
  const fakeApi = {
    raw: {
      sendRichMessageDraft: async (params) => { calls.push(params); return true; },
    },
  };

  const ok = await trySendDraft(fakeApi, 456, 2, "# Title\nBody", true);
  assert("rich draft returns true", ok);
