// AB-7 smoke: goal continuation decision flow.
//
// Can't drive the real bot (would need mock Telegram). Instead we
// replay the decision logic from runPrompt's post-reply section:
//
//   1. transformReplyTokens(replyBuffer) → { skillUsages, goalDone }
//   2. If goalDone && goalActive → markDone, bodyFinal += "✓ Goal achieved"
//   3. Else if !goalDone && goalActive:
//        a. incrementTurn(reason)
//        b. If pausedByBudget → bodyFinal += "⏸ Goal paused", no continuation
//        c. Else → continuationPlan set for next turn
//
// We also simulate a multi-turn session: set goal → reply 1 (no done) →
// continuation plan generated; run a "continuation turn" → reply 2 (done)
// → achievement. Plus budget-exhausted scenario.
//
// Run: node scripts/check-ab7-goal-loop.mjs

import { mkdir, rm } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import { transform } from "../dist/observerTransformer.js";
import * as goalStore from "../dist/goalStore.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const tmpRoot = path.join(__dirname, "..", "tmp", "check-ab7-goal-loop");
const memoryDir = path.join(tmpRoot, "memory");

async function fresh() {
  await rm(tmpRoot, { recursive: true, force: true });
  await mkdir(memoryDir, { recursive: true });
}

const results = [];
function ok(name) { results.push({ name, pass: true }); console.log(`[PASS] ${name}`); }
function fail(name, detail) { results.push({ name, pass: false, detail }); console.error(`[FAIL] ${name}: ${detail}`); }

/** Mirror of the runPrompt post-reply goal flow, minus Telegram.
 * Returns what the body additions + continuation plan would look like. */
async function simulateTurn(chatId, replyBuffer, { isContinuation = false } = {}) {
  const ab7 = transform(replyBuffer);

  let goalAchievementLine = null;
  let continuationPlan = null;

  if (ab7.goalDone) {
    const active = await goalStore.isActive(memoryDir, chatId);
    if (active) {
      const s = await goalStore.markDone(memoryDir, chatId, ab7.goalDone.reason);
      goalAchievementLine = `\n\n✓ Goal achieved: ${s.last_reason}`;
    } else {
      // fail-open: strip, warn, no state change (transformer already stripped)
    }
  } else if (!isContinuation) {
    const gs = await goalStore.get(memoryDir, chatId);
    if (gs && gs.status === "active") {
      const result = await goalStore.incrementTurn(
        memoryDir, chatId,
        replyBuffer ? replyBuffer.slice(0, 200) : undefined,
      );
      if (result.pausedByBudget) {
        goalAchievementLine =
          `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used.`;
      } else {
        continuationPlan = {
          turnIndex: result.state.turns_used + 1,
          maxTurns: result.state.max_turns,
          objective: result.state.objective,
          lastReason: result.state.last_reason,
        };
      }
    }
  } else {
    // Continuation turn: same incrementTurn logic, just with isContinuation flag
    const gs = await goalStore.get(memoryDir, chatId);
    if (gs && gs.status === "active") {
      const result = await goalStore.incrementTurn(
        memoryDir, chatId,
        replyBuffer ? replyBuffer.slice(0, 200) : undefined,
      );
      if (result.pausedByBudget) {
        goalAchievementLine =
          `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used.`;
      } else {
        continuationPlan = {
          turnIndex: result.state.turns_used + 1,
          maxTurns: result.state.max_turns,
          objective: result.state.objective,
          lastReason: result.state.last_reason,
        };
      }
    }
  }

  return {
    displayText: ab7.text,
    skillUsages: ab7.skillUsages,
    goalDone: ab7.goalDone,
    goalAchievementLine,
    continuationPlan,
  };
}

// ───────────────────────────────────────────────────────────────────────
// 1. No active goal → any reply passes through, no plan
// ───────────────────────────────────────────────────────────────────────
await fresh();
{
  const out = await simulateTurn(1001, "plain reply, no tokens");
  if (!out.goalAchievementLine && !out.continuationPlan &&
      out.displayText === "plain reply, no tokens") {
    ok("1. no active goal → no plan");
  } else {
    fail("1. no active goal → no plan", JSON.stringify(out));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 2. Active goal, no GOAL_DONE, budget > 1 → continuation planned
// ───────────────────────────────────────────────────────────────────────

