// editNow 並發互斥 smoke：coalesceAsyncRunner（src/async-coalesce.ts）。
//
// 背景（2026-07-11 roadmap 事故）：streaming editNow 被 onUpdate（每 chunk）
// 多路 fire-and-forget 觸發、無 in-flight 鎖。draft 送出失敗期間，並發呼叫
// 在「trySendDraft 失敗 → !placeholder → sendMessage」降級分支各自建立
// placeholder，一口氣冒出十幾則相同內容訊息。
//
// 這裡直測 shipped helper：並發合併、trailing 補跑、取消語意，並用
// 「placeholder 降級」情境重演事故（無鎖 = N 則；有鎖 = 1 則）。
//
// Run: node scripts/check-editnow-race.mjs

import { readFileSync } from "node:fs";
import ts from "typescript";

const source = readFileSync("src/async-coalesce.ts", "utf8");
const js = ts.transpileModule(source, {
  compilerOptions: { module: ts.ModuleKind.ES2022, target: ts.ScriptTarget.ES2022 },
}).outputText;
const { coalesceAsyncRunner } = await import(
  `data:text/javascript;base64,${Buffer.from(js).toString("base64")}`
);

let passed = 0;
function assert(name, condition, detail = "") {
  if (!condition) {
    console.error(`[FAIL] ${name}${detail ? `: ${detail}` : ""}`);
    process.exit(1);
  }
  passed++;
  console.log(`[PASS] ${name}`);
}
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

// ─── 1. 事故重演：placeholder 降級分支，10 路並發只建 1 則 ───
{
  let placeholder;
  let messagesSent = 0;
  const body = async () => {
    // 模擬 trySendDraft 失敗（有 await gap）
    await sleep(5);
    if (!placeholder) {
      // 模擬 sendMessage 網路延遲（第二個 await gap — 原事故的 TOCTOU 窗口）
      await sleep(10);
      messagesSent++;
      placeholder = { message_id: messagesSent };
    }
  };

  // 無鎖版本先證明 race 真的存在（10 路並發 → 10 則）
  const naiveRuns = Array.from({ length: 10 }, () => body());
  await Promise.all(naiveRuns);
  assert("無鎖版本重現事故（10 並發 → 10 則訊息）", messagesSent === 10,
    `messagesSent=${messagesSent}`);

  // 有鎖版本：同樣 10 路並發 → 只有 1 則
  placeholder = undefined;
  messagesSent = 0;
  const editNow = coalesceAsyncRunner(body);
  const runs = Array.from({ length: 10 }, () => editNow());
  await Promise.all(runs);
  await sleep(40); // 等 trailing 補跑完
  assert("coalesce 版本 10 並發只建 1 則 placeholder", messagesSent === 1,
    `messagesSent=${messagesSent}`);
}

// ─── 2. 並發合併：burst 期間的觸發合併成「1 次執行 + 1 次補跑」 ───
{
  let executions = 0;
  const editNow = coalesceAsyncRunner(async () => {
    executions++;
